   1→import { createContext, useContext, useReducer } from 'react';
   2→import { createProject } from '@/domain/models';
   3→import { clearProjectPhaseReferences } from '@/domain/phaseAssignments';
   4→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
   5→import { sortPhases } from '@/domain/phaseModels';
   6→import { getRoofAttachmentElevation, syncProjectRoofSystem } from '@/domain/roofModels';
   7→import { syncProjectTrussSystems } from '@/domain/trussModels';
   8→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
   9→import { syncStairLandingAttachment } from '@/geometry/landingGeometry';
  10→import { clampWallOpeningOffset, wallLength } from '@/geometry/wallGeometry';
  11→
  12→const ProjectContext = createContext(null);
  13→const HISTORY_LIMIT = 100;
  14→
  15→function snapshotProject(project) {
  16→  return JSON.stringify(project);
  17→}
  18→
  19→function syncProjectStructures(project) {
  20→  return syncProjectRoofSystem(syncProjectTrussSystems(project));
  21→}
  22→
  23→function applyProjectUpdate(state, nextProject, recordHistory = true) {
  24→  const syncedProject = syncProjectStructures(nextProject);
  25→  const nextSnapshot = snapshotProject(syncedProject);
  26→  const history = recordHistory
  27→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
  28→    : state.history;
  29→
  30→  return {
  31→    ...state,
  32→    history,
  33→    future: recordHistory ? [] : state.future,
  34→    project: syncedProject,
  35→    isDirty: nextSnapshot !== state.savedSnapshot,
  36→  };
  37→}
  38→
  39→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
  40→  const nextFloors = state.project.floors.map((floor) => (
  41→    floor.id === floorId ? updater(floor) : floor
  42→  ));
  43→
  44→  return applyProjectUpdate(state, {
  45→    ...state.project,
  46→    updatedAt: new Date().toISOString(),
  47→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
  48→  }, recordHistory);
  49→}
  50→
  51→function replaceFloors(state, floors, recordHistory = true) {
  52→  return applyProjectUpdate(state, {
  53→    ...state.project,
  54→    updatedAt: new Date().toISOString(),
  55→    floors: sortFloors(floors),
  56→  }, recordHistory);
  57→}
  58→
  59→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
  60→  return {
  61→    ...project,
  62→    floors: project.floors.map((floor) => ({
  63→      ...floor,
  64→      stairs: (floor.stairs || []).map((stair) => ({
  65→        ...stair,
  66→        floorRelation: {
  67→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
  68→            ? fallbackFloorId
  69→            : (stair.floorRelation?.fromFloorId ?? floor.id),
  70→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
  71→            ? fallbackFloorId
  72→            : (stair.floorRelation?.toFloorId ?? floor.id),
  73→        },
  74→      })),
  75→    })),
  76→    sheets: (project.sheets || []).map((sheet) => ({
  77→      ...sheet,
  78→      viewports: (sheet.viewports || []).map((viewport) => ({
  79→        ...viewport,
  80→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
  81→          ? fallbackFloorId
  82→          : viewport.sourceFloorId,
  83→        sourceRefId: viewport.sourceFloorId === deletedFloorId
  84→          ? null
  85→          : viewport.sourceRefId,
  86→      })),
  87→    })),
  88→  };
  89→}
  90→
  91→function clearStairRoofAccessReferences(project, roofOpeningId = null) {
  92→  return {
  93→    ...project,
  94→    floors: (project.floors || []).map((floor) => ({
  95→      ...floor,
  96→      stairs: (floor.stairs || []).map((stair) => {
  97→        const currentRoofOpeningId = stair.roofAccess?.roofOpeningId || null;
  98→        if (!currentRoofOpeningId) return stair;
  99→        if (roofOpeningId && currentRoofOpeningId !== roofOpeningId) return stair;
 100→        return {
 101→          ...stair,
 102→          roofAccess: null,
 103→        };
 104→      }),
 105→    })),
 106→  };
 107→}
 108→
 109→function updateRoofSystem(state, updater, recordHistory = true) {
 110→  const nextRoofSystem = updater(state.project.roofSystem);
 111→  return applyProjectUpdate(state, {
 112→    ...state.project,
 113→    updatedAt: new Date().toISOString(),
 114→    roofSystem: nextRoofSystem,
 115→  }, recordHistory);
 116→}
 117→
 118→function updateTrussSystems(state, updater, recordHistory = true) {
 119→  const nextTrussSystems = updater(state.project.trussSystems || []);
 120→  return applyProjectUpdate(state, {
 121→    ...state.project,
 122→    updatedAt: new Date().toISOString(),
 123→    trussSystems: nextTrussSystems,
 124→  }, recordHistory);
 125→}
 126→
 127→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 128→  const nextWall = { ...existingWall, ...wallUpdate };
 129→
 130→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 131→    nextWall.startAttachment = null;
 132→  }
 133→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 134→    nextWall.endAttachment = null;
 135→  }
 136→
 137→  return syncWallAttachmentPoints(nextWall, columns);
 138→}
 139→
 140→function clampWallMountedOpenings(openings, wallId, nextWallLength) {
 141→  return openings.map((opening) => {
 142→    if (opening.wallId !== wallId) return opening;
 143→
 144→    const nextOffset = clampWallOpeningOffset(nextWallLength, opening.width, opening.offset);
 145→    return nextOffset === opening.offset ? opening : { ...opening, offset: nextOffset };
 146→  });
 147→}
 148→
 149→function projectReducer(state, action) {
 150→  switch (action.type) {
 151→    case 'PROJECT_NEW': {
 152→      const newProject = syncProjectStructures({
 153→        ...action.project,
 154→        floors: sortFloors(action.project.floors || []),
 155→      });
 156→      return {
 157→        project: newProject,
 158→        isDirty: false,
 159→        lastSavedAt: null,
 160→        savedSnapshot: snapshotProject(newProject),
 161→        history: [],
 162→        future: [],
 163→      };
 164→    }
 165→
 166→    case 'PROJECT_LOAD': {
 167→      const loadedProject = syncProjectStructures({
 168→        ...action.project,
 169→        floors: sortFloors(action.project.floors || []),
 170→      });
 171→      return {
 172→        project: loadedProject,
 173→        isDirty: false,
 174→        lastSavedAt: action.savedAt || null,
 175→        savedSnapshot: snapshotProject(loadedProject),
 176→        history: [],
 177→        future: [],
 178→      };
 179→    }
 180→
 181→    case 'PROJECT_SET_NAME':
 182→      return applyProjectUpdate(state, {
 183→        ...state.project,
 184→        name: action.name,
 185→        updatedAt: new Date().toISOString(),
 186→      });
 187→
 188→    case 'PROJECT_UPDATE':
 189→      return applyProjectUpdate(state, {
 190→        ...state.project,
 191→        ...action.updates,
 192→        updatedAt: new Date().toISOString(),
 193→      });
 194→
 195→    case 'ROOF_CREATE':
 196→      return updateRoofSystem(state, () => action.roofSystem);
 197→
 198→    case 'ROOF_UPDATE':
 199→      return updateRoofSystem(state, (roofSystem) => {
 200→        if (!roofSystem || roofSystem.id !== action.roofSystem.id) return roofSystem;
 201→
 202→        const mergedRoofSystem = {
 203→          ...roofSystem,
 204→          ...action.roofSystem,
 205→        };
 206→        const trussAttachmentChanged = Object.prototype.hasOwnProperty.call(action.roofSystem, 'trussAttachmentId')
 207→          && (action.roofSystem.trussAttachmentId || null) !== (roofSystem.trussAttachmentId || null);
 208→
 209→        if (trussAttachmentChanged && !Object.prototype.hasOwnProperty.call(action.roofSystem, 'baseElevation')) {
 210→          const attachmentBaseElevation = getRoofAttachmentElevation(state.project, mergedRoofSystem);
 211→          mergedRoofSystem.attachmentOffset = mergedRoofSystem.trussAttachmentId
 212→            ? 0
 213→            : ((roofSystem.baseElevation ?? attachmentBaseElevation) - attachmentBaseElevation);
 214→          if (!Object.prototype.hasOwnProperty.call(action.roofSystem, 'pitchSource')) {
 215→            mergedRoofSystem.pitchSource = mergedRoofSystem.trussAttachmentId ? 'truss' : 'manual';
 216→          }
 217→        }
 218→
 219→        if ('baseElevation' in action.roofSystem) {
 220→          const attachmentBaseElevation = getRoofAttachmentElevation(state.project, mergedRoofSystem);
 221→          mergedRoofSystem.attachmentOffset = (action.roofSystem.baseElevation ?? roofSystem.baseElevation)
 222→            - attachmentBaseElevation;
 223→        }
 224→
 225→        if (
 226→          Object.prototype.hasOwnProperty.call(action.roofSystem, 'pitch')
 227→          && mergedRoofSystem.trussAttachmentId
 228→          && !Object.prototype.hasOwnProperty.call(action.roofSystem, 'pitchSource')
 229→          && Number(action.roofSystem.pitch?.slope ?? roofSystem.pitch?.slope) !== Number(roofSystem.pitch?.slope)
 230→        ) {
 231→          mergedRoofSystem.pitchSource = 'manual';
 232→        }
 233→
 234→        return mergedRoofSystem;
 235→      });
 236→
 237→    case 'ROOF_DELETE':
 238→      return applyProjectUpdate(state, {
 239→        ...clearStairRoofAccessReferences(state.project),
 240→        updatedAt: new Date().toISOString(),
 241→        roofSystem: null,
 242→      });
 243→
 244→    case 'TRUSS_SYSTEM_ADD':
 245→      return updateTrussSystems(state, (trussSystems) => [...trussSystems, action.trussSystem]);
 246→
 247→    case 'TRUSS_SYSTEM_UPDATE':
 248→      return updateTrussSystems(state, (trussSystems) => (
 249→        trussSystems.map((trussSystem) => {
 250→          if (trussSystem.id !== action.trussSystem.id) return trussSystem;
 251→          const nextFloorId = action.trussSystem.floorId ?? trussSystem.floorId;
 252→          return {
 253→            ...trussSystem,
 254→            ...action.trussSystem,
 255→            trussInstances: (action.trussSystem.trussInstances || trussSystem.trussInstances || []).map((trussInstance) => ({
 256→              ...trussInstance,
 257→              floorId: nextFloorId,
 258→            })),
 259→          };
 260→        })
 261→      ));
 262→
 263→    case 'TRUSS_SYSTEM_DELETE':
 264→      return updateTrussSystems(state, (trussSystems) => (
 265→        trussSystems.filter((trussSystem) => trussSystem.id !== action.trussSystemId)
 266→      ));
 267→
 268→    case 'TRUSS_INSTANCE_ADD':
 269→      return updateTrussSystems(state, (trussSystems) => (
 270→        trussSystems.map((trussSystem) => (
 271→          trussSystem.id === action.trussSystemId
 272→            ? {
 273→                ...trussSystem,
 274→                trussInstances: [...(trussSystem.trussInstances || []), action.trussInstance],
 275→              }
 276→            : trussSystem
 277→        ))
 278→      ));
 279→
 280→    case 'TRUSS_INSTANCE_UPDATE':
 281→      return updateTrussSystems(state, (trussSystems) => (
 282→        trussSystems.map((trussSystem) => (
 283→          trussSystem.id === action.trussSystemId
 284→            ? {
 285→                ...trussSystem,
 286→                trussInstances: (trussSystem.trussInstances || []).map((trussInstance) => (
 287→                  trussInstance.id === action.trussInstance.id
 288→                    ? { ...trussInstance, ...action.trussInstance, floorId: trussSystem.floorId }
 289→                    : trussInstance
 290→                )),
 291→              }
 292→            : trussSystem
 293→        ))
 294→      ));
 295→
 296→    case 'TRUSS_INSTANCE_DELETE':
 297→      return updateTrussSystems(state, (trussSystems) => (
 298→        trussSystems.map((trussSystem) => (
 299→          trussSystem.id === action.trussSystemId
 300→            ? {
 301→                ...trussSystem,
 302→                trussInstances: (trussSystem.trussInstances || []).filter((trussInstance) => trussInstance.id !== action.trussInstanceId),
 303→              }
 304→            : trussSystem
 305→        ))
 306→      ));
 307→
 308→    case 'PARAPET_ADD':
 309→      return updateRoofSystem(state, (roofSystem) => (
 310→        roofSystem
 311→          ? { ...roofSystem, parapets: [...(roofSystem.parapets || []), action.parapet] }
 312→          : roofSystem
 313→      ));
 314→
 315→    case 'PARAPET_UPDATE':
 316→      return updateRoofSystem(state, (roofSystem) => (
 317→        roofSystem
 318→          ? {
 319→              ...roofSystem,
 320→              parapets: (roofSystem.parapets || []).map((parapet) => (
 321→                parapet.id === action.parapet.id ? { ...parapet, ...action.parapet } : parapet
 322→              )),
 323→            }
 324→          : roofSystem
 325→      ));
 326→
 327→    case 'PARAPET_DELETE':
 328→      return updateRoofSystem(state, (roofSystem) => (
 329→        roofSystem
 330→          ? {
 331→              ...roofSystem,
 332→              parapets: (roofSystem.parapets || []).filter((parapet) => parapet.id !== action.parapetId),
 333→            }
 334→          : roofSystem
 335→      ));
 336→
 337→    case 'DRAIN_ADD':
 338→      return updateRoofSystem(state, (roofSystem) => (
 339→        roofSystem
 340→          ? { ...roofSystem, drains: [...(roofSystem.drains || []), action.drain] }
 341→          : roofSystem
 342→      ));
 343→
 344→    case 'DRAIN_UPDATE':
 345→      return updateRoofSystem(state, (roofSystem) => (
 346→        roofSystem
 347→          ? {
 348→              ...roofSystem,
 349→              drains: (roofSystem.drains || []).map((drain) => (
 350→                drain.id === action.drain.id ? { ...drain, ...action.drain } : drain
 351→              )),
 352→            }
 353→          : roofSystem
 354→      ));
 355→
 356→    case 'DRAIN_DELETE':
 357→      return updateRoofSystem(state, (roofSystem) => (
 358→        roofSystem
 359→          ? {
 360→              ...roofSystem,
 361→              drains: (roofSystem.drains || []).filter((drain) => drain.id !== action.drainId),
 362→            }
 363→          : roofSystem
 364→      ));
 365→
 366→    case 'ROOF_OPENING_ADD':
 367→      return updateRoofSystem(state, (roofSystem) => (
 368→        roofSystem
 369→          ? { ...roofSystem, roofOpenings: [...(roofSystem.roofOpenings || []), action.roofOpening] }
 370→          : roofSystem
 371→      ));
 372→
 373→    case 'ROOF_OPENING_UPDATE':
 374→      return updateRoofSystem(state, (roofSystem) => (
 375→        roofSystem
 376→          ? {
 377→              ...roofSystem,
 378→              roofOpenings: (roofSystem.roofOpenings || []).map((roofOpening) => (
 379→                roofOpening.id === action.roofOpening.id ? { ...roofOpening, ...action.roofOpening } : roofOpening
 380→              )),
 381→            }
 382→          : roofSystem
 383→      ));
 384→
 385→    case 'ROOF_OPENING_DELETE':
 386→      return applyProjectUpdate(state, clearStairRoofAccessReferences({
 387→        ...state.project,
 388→        updatedAt: new Date().toISOString(),
 389→        roofSystem: state.project.roofSystem
 390→          ? {
 391→              ...state.project.roofSystem,
 392→              roofOpenings: (state.project.roofSystem.roofOpenings || []).filter((roofOpening) => roofOpening.id !== action.roofOpeningId),
 393→            }
 394→          : null,
 395→      }, action.roofOpeningId));
 396→
 397→    case 'ROOF_PLANE_ADD':
 398→      return updateRoofSystem(state, (roofSystem) => (
 399→        roofSystem
 400→          ? { ...roofSystem, roofPlanes: [...(roofSystem.roofPlanes || []), action.roofPlane] }
 401→          : roofSystem
 402→      ));
 403→
 404→    case 'ROOF_PLANE_UPDATE':
 405→      return updateRoofSystem(state, (roofSystem) => (
 406→        roofSystem
 407→          ? {
 408→              ...roofSystem,
 409→              roofPlanes: (roofSystem.roofPlanes || []).map((roofPlane) => (
 410→                roofPlane.id === action.roofPlane.id ? { ...roofPlane, ...action.roofPlane } : roofPlane
 411→              )),
 412→            }
 413→          : roofSystem
 414→      ));
 415→
 416→    case 'ROOF_PLANE_DELETE':
 417→      return updateRoofSystem(state, (roofSystem) => (
 418→        roofSystem
 419→          ? {
 420→              ...roofSystem,
 421→              roofPlanes: (roofSystem.roofPlanes || []).filter((roofPlane) => roofPlane.id !== action.roofPlaneId),
 422→              roofEdges: (roofSystem.roofEdges || []).filter((roofEdge) => !((roofEdge.planeIds || []).includes(action.roofPlaneId))),
 423→            }
 424→          : roofSystem
 425→      ));
 426→
 427→    case 'ROOF_EDGE_UPDATE':
 428→      return updateRoofSystem(state, (roofSystem) => {
 429→        if (!roofSystem) return roofSystem;
 430→
 431→        const existingEdges = roofSystem.roofEdges || [];
 432→        const existingIndex = existingEdges.findIndex((roofEdge) => (
 433→          roofEdge.id === action.roofEdge.id
 434→          || (action.roofEdge.geometryKey && roofEdge.geometryKey === action.roofEdge.geometryKey)
 435→        ));
 436→
 437→        if (existingIndex === -1) {
 438→          return {
 439→            ...roofSystem,
 440→            roofEdges: [...existingEdges, action.roofEdge],
 441→          };
 442→        }
 443→
 444→        return {
 445→          ...roofSystem,
 446→          roofEdges: existingEdges.map((roofEdge, index) => (
 447→            index === existingIndex ? { ...roofEdge, ...action.roofEdge } : roofEdge
 448→          )),
 449→        };
 450→      });
 451→
 452→    case 'ROOF_EDGE_DELETE':
 453→      return updateRoofSystem(state, (roofSystem) => (
 454→        roofSystem
 455→          ? {
 456→              ...roofSystem,
 457→              roofEdges: (roofSystem.roofEdges || []).filter((roofEdge) => (
 458→                roofEdge.id !== action.roofEdgeId
 459→                && (action.geometryKey ? roofEdge.geometryKey !== action.geometryKey : true)
 460→              )),
 461→            }
 462→          : roofSystem
 463→      ));
 464→
 465→    case 'FLOOR_ADD':
 466→      return replaceFloors(state, [...state.project.floors, action.floor]);
 467→
 468→    case 'FLOOR_UPDATE':
 469→      return applyProjectUpdate(state, (() => {
 470→        let elevationDelta = 0;
 471→        const nextFloors = state.project.floors.map((floor) => {
 472→          if (floor.id !== action.floor.id) return floor;
 473→
 474→          const mergedFloor = {
 475→            ...floor,
 476→            ...action.floor,
 477→          };
 478→          const nextElevation = getFloorElevation(mergedFloor);
 479→          elevationDelta = nextElevation - getFloorElevation(floor);
 480→          return {
 481→            ...shiftFloorAbsoluteElements({
 482→              ...mergedFloor,
 483→              elevation: getFloorElevation(floor),
 484→            }, elevationDelta),
 485→            elevation: nextElevation,
 486→          };
 487→        });
 488→
 489→        const nextTrussSystems = (state.project.trussSystems || []).map((trussSystem) => (
 490→          trussSystem.floorId === action.floor.id
 491→            ? {
 492→                ...trussSystem,
 493→                baseElevation: (trussSystem.baseElevation ?? 0) + elevationDelta,
 494→              }
 495→            : trussSystem
 496→        ));
 497→
 498→        return {
 499→          ...state.project,
 500→          updatedAt: new Date().toISOString(),
 501→          floors: sortFloors(nextFloors),
 502→          trussSystems: nextTrussSystems,
 503→        };
 504→      })());
 505→
 506→    case 'FLOOR_DUPLICATE': {
 507→      const duplicatedFloor = action.floor;
 508→      const elevationShift = duplicatedFloor.floorToFloorHeight ?? 0;
 509→      const insertionLevelIndex = getFloorLevelIndex(duplicatedFloor);
 510→
 511→      const shiftedFloors = state.project.floors.map((floor) => {
 512→        if (getFloorLevelIndex(floor) < insertionLevelIndex) return floor;
 513→
 514→        const previousLevelIndex = getFloorLevelIndex(floor);
 515→        return shiftFloorElevationData({
 516→          ...floor,
 517→          name: floor.name === getDefaultFloorName(previousLevelIndex)
 518→            ? getDefaultFloorName(previousLevelIndex + 1)
 519→            : floor.name,
 520→          levelIndex: previousLevelIndex + 1,
 521→        }, elevationShift);
 522→      });
 523→
 524→      return replaceFloors(state, [...shiftedFloors, duplicatedFloor]);
 525→    }
 526→
 527→    case 'FLOOR_DELETE': {
 528→      if (state.project.floors.length <= 1) return state;
 529→
 530→      const nextProject = replaceDeletedFloorReferences(
 531→        {
 532→          ...state.project,
 533→          floors: state.project.floors.filter((floor) => floor.id !== action.floorId),
 534→          trussSystems: (state.project.trussSystems || []).filter((trussSystem) => trussSystem.floorId !== action.floorId),
 535→        },
 536→        action.floorId,
 537→        action.fallbackFloorId
 538→      );
 539→
 540→      return applyProjectUpdate(state, {
 541→        ...nextProject,
 542→        updatedAt: new Date().toISOString(),
 543→        floors: sortFloors(nextProject.floors),
 544→      });
 545→    }
 546→
 547→    case 'SHEET_ADD':
 548→      return applyProjectUpdate(state, {
 549→        ...state.project,
 550→        updatedAt: new Date().toISOString(),
 551→        sheets: [...(state.project.sheets || []), action.sheet],
 552→      });
 553→
 554→    case 'SHEET_UPDATE':
 555→      return applyProjectUpdate(state, {
 556→        ...state.project,
 557→        updatedAt: new Date().toISOString(),
 558→        sheets: (state.project.sheets || []).map((sheet) => (
 559→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
 560→        )),
 561→      });
 562→
 563→    case 'SHEET_DELETE':
 564→      return applyProjectUpdate(state, {
 565→        ...state.project,
 566→        updatedAt: new Date().toISOString(),
 567→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
 568→      });
 569→
 570→    case 'SHEET_VIEWPORT_ADD':
 571→      return applyProjectUpdate(state, {
 572→        ...state.project,
 573→        updatedAt: new Date().toISOString(),
 574→        sheets: (state.project.sheets || []).map((sheet) => (
 575→          sheet.id === action.sheetId
 576→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
 577→            : sheet
 578→        )),
 579→      });
 580→
 581→    case 'SHEET_VIEWPORT_UPDATE':
 582→      return applyProjectUpdate(state, {
 583→        ...state.project,
 584→        updatedAt: new Date().toISOString(),
 585→        sheets: (state.project.sheets || []).map((sheet) => (
 586→          sheet.id === action.sheetId
 587→            ? {
 588→                ...sheet,
 589→                viewports: (sheet.viewports || []).map((viewport) => (
 590→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
 591→                )),
 592→              }
 593→            : sheet
 594→        )),
 595→      });
 596→
 597→    case 'SHEET_VIEWPORT_DELETE':
 598→      return applyProjectUpdate(state, {
 599→        ...state.project,
 600→        updatedAt: new Date().toISOString(),
 601→        sheets: (state.project.sheets || []).map((sheet) => (
 602→          sheet.id === action.sheetId
 603→            ? {
 604→                ...sheet,
 605→                viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId),
 606→              }
 607→            : sheet
 608→        )),
 609→      });
 610→
 611→    case 'WALL_ADD':
 612→      return updateFloor(state, action.floorId, f => ({
 613→        ...f,
 614→        walls: [...f.walls, syncWallAttachmentPoints(action.wall, f.columns || [])],
 615→      }));
