1026→export function ProjectProvider({ children, initialProject }) {
1027→  const [state, dispatch] = useReducer(
1028→    projectReducer,
1029→    initialProject || createProject(),
1030→    createInitialState
1031→  );
1032→  return (
1033→    <ProjectContext.Provider value={{ state, dispatch }}>
1034→      {children}
1035→    </ProjectContext.Provider>
1036→  );
1037→}
