1039→export function useProject() {
1040→  const ctx = useContext(ProjectContext);
1041→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
1042→  const { state, dispatch } = ctx;
1043→
1044→  const duplicateFloor = (floorId) => {
1045→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
1046→    return floor ? createDuplicatedFloor(floor) : null;
1047→  };
1048→
1049→  return {
1050→    project: state.project,
1051→    isDirty: state.isDirty,
1052→    lastSavedAt: state.lastSavedAt,
1053→    canUndo: state.history.length > 0,
1054→    canRedo: state.future.length > 0,
1055→    dispatch,
1056→    duplicateFloor,
1057→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
1058→  };
1059→}
