 37→function DimensionFigure({ figure }) {
 38→  const fontSize = DRAWING_GRAPHICS.annotation.textSize;
 39→
 40→  return (
 41→    <g key={figure.id}>
 42→      {figure.extensionLines.map((line, index) => (
 43→        <line
 44→          key={`${figure.id}-ext-${index}`}
 45→          x1={line.start.x}
 46→          y1={line.start.y}
 47→          x2={line.end.x}
 48→          y2={line.end.y}
 49→          stroke={DRAWING_GRAPHICS.annotation.dimensionExtension}
 50→          strokeWidth={DRAWING_GRAPHICS.annotation.dimensionExtensionWidth}
 51→          vectorEffect="non-scaling-stroke"
 52→        />
 53→      ))}
 54→      <line
 55→        x1={figure.lineStart.x}
 56→        y1={figure.lineStart.y}
 57→        x2={figure.lineEnd.x}
 58→        y2={figure.lineEnd.y}
 59→        stroke={DRAWING_GRAPHICS.annotation.dimensionStroke}
 60→        strokeWidth={DRAWING_GRAPHICS.annotation.dimensionStrokeWidth}
 61→        vectorEffect="non-scaling-stroke"
 62→      />
 63→      {figure.arrowheads.map((arrow, index) => (
 64→        <Arrowhead key={`${figure.id}-arrow-${index}`} arrow={arrow} />
 65→      ))}
