 83→
 84→function TagTextMask({ tag, fontSize, lineHeight, opacity = 0.92 }) {
 85→  const maxLineLength = Math.max(...tag.textLines.map((line) => String(line || '').length), 1);
 86→  const width = estimateTextWidth('X'.repeat(maxLineLength), fontSize) + (tag.maskPaddingX ?? 44);
 87→  const height = Math.max(lineHeight, tag.textLines.length * lineHeight) + (tag.maskPaddingY ?? 22);
 88→  const x = tag.textAnchor === 'start'
 89→    ? tag.position.x
 90→    : (tag.textAnchor === 'end' ? tag.position.x - width : tag.position.x - (width / 2));
 91→
 92→  return (
 93→    <rect
 94→      x={x}
 95→      y={tag.position.y - height / 2}
 96→      width={width}
 97→      height={height}
 98→      fill={SHEET_COLORS.mask}
 99→      opacity={opacity}
100→      transform={`rotate(${tag.angle || 0}, ${tag.position.x}, ${tag.position.y})`}
101→    />
102→  );
103→}
