124→export function useSketchEditor() {
125→  const ctx = useContext(SketchEditorContext);
126→  if (!ctx) throw new Error('useSketchEditor must be used within SketchEditorProvider');
127→  return { ...ctx.state, dispatch: ctx.dispatch };
